    /**
     * Process a Base64-encoded SAML response string.
     */
    public AuthenticatedSession processSamlResponse(String base64EncodedResponse) throws SamlProcessingException {
        if (base64EncodedResponse == null || base64EncodedResponse.trim().isEmpty()) {
            throw new SamlProcessingException("SAML response is null or empty");
        }

        String xmlResponse = decodeBase64(base64EncodedResponse);
        Document document = parseXml(xmlResponse);
        SamlResponse samlResponse = validateAndExtractResponse(document);
        return createAuthenticatedSession(samlResponse);
    }

    /**
     * Process a raw XML SAML response string (not base64 encoded).
     */
    public AuthenticatedSession processRawSamlResponse(String xmlResponse) throws SamlProcessingException {
        if (xmlResponse == null || xmlResponse.trim().isEmpty()) {
            throw new SamlProcessingException("SAML response XML is null or empty");
        }

        Document document = parseXml(xmlResponse);
        SamlResponse samlResponse = validateAndExtractResponse(document);
        return createAuthenticatedSession(samlResponse);
    }

    private String decodeBase64(String encoded) throws SamlProcessingException {
        try {
            byte[] decodedBytes = Base64.getDecoder().decode(encoded.trim());
            return new String(decodedBytes, StandardCharsets.UTF_8);
        } catch (IllegalArgumentException e) {
            throw new SamlProcessingException("Failed to decode Base64 SAML response", e);
        }
    }

    private Document parseXml(String xml) throws SamlProcessingException {
        try {
            DocumentBuilderFactory factory = DocumentBuilderFactory.newInstance();
            factory.setNamespaceAware(true);

            // Security: Disable external entities to prevent XXE attacks
            factory.setFeature("http://apache.org/xml/features/disallow-doctype-decl", true);
            factory.setFeature("http://xml.org/sax/features/external-general-entities", false);
            factory.setFeature("http://xml.org/sax/features/external-parameter-entities", false);
            factory.setFeature("http://apache.org/xml/features/nonvalidating/load-external-dtd", false);
            factory.setXIncludeAware(false);
            factory.setExpandEntityReferences(false);

            DocumentBuilder builder = factory.newDocumentBuilder();
            InputSource inputSource = new InputSource(new StringReader(xml));
            return builder.parse(inputSource);
        } catch (ParserConfigurationException | SAXException | IOException e) {
            throw new SamlProcessingException("Failed to parse SAML XML response", e);
        }
    }

    private SamlResponse validateAndExtractResponse(Document document) throws SamlProcessingException {
        Element rootElement = document.getDocumentElement();

        // Validate root element is a SAML Response
        validateResponseElement(rootElement);

        // Extract Response attributes
        String responseId = rootElement.getAttribute("ID");
        String destination = rootElement.getAttribute("Destination");
        String issueInstantStr = rootElement.getAttribute("IssueInstant");
        String inResponseTo = rootElement.getAttribute("InResponseTo");

        if (responseId == null || responseId.isEmpty()) {
            throw new SamlProcessingException("SAML Response missing required 'ID' attribute");
        }

        if (issueInstantStr == null || issueInstantStr.isEmpty()) {
            throw new SamlProcessingException("SAML Response missing required 'IssueInstant' attribute");
        }

        Instant issueInstant = parseInstant(issueInstantStr);

        // Validate destination if configured
        if (configuration.getExpectedDestination() != null && !configuration.getExpectedDestination().isEmpty()) {
            if (!configuration.getExpectedDestination().equals(destination)) {
                throw new SamlProcessingException(
                        "SAML Response destination mismatch. Expected: " + configuration.getExpectedDestination()
                                + ", Got: " + destination);
            }
        }

        // Validate status
        validateStatus(rootElement);

        // Extract Issuer
        String issuer = extractIssuer(rootElement);
        if (configuration.getExpectedIssuer() != null && !configuration.getExpectedIssuer().isEmpty()) {
            if (!configuration.getExpectedIssuer().equals(issuer)) {
                throw new SamlProcessingException(
                        "SAML Response issuer mismatch. Expected: " + configuration.getExpectedIssuer()
                                + ", Got: " + issuer);
            }
        }

        // Extract Assertions
        List<SamlAssertion> assertions = extractAssertions(rootElement);
        if (assertions.isEmpty()) {
            throw new SamlProcessingException("SAML Response contains no assertions");
        }

        SamlResponse samlResponse = new SamlResponse();
        samlResponse.setId(responseId);
        samlResponse.setDestination(destination);
        samlResponse.setIssueInstant(issueInstant);
        samlResponse.setInResponseTo(inResponseTo);
        samlResponse.setIssuer(issuer);
        samlResponse.setAssertions(assertions);

        return samlResponse;
    }

    private void validateResponseElement(Element rootElement) throws SamlProcessingException {
        String localName = rootElement.getLocalName();
        String namespaceURI = rootElement.getNamespaceURI();

        if (!"Response".equals(localName)) {
            throw new SamlProcessingException(
                    "Root element is not a SAML Response. Found: " + localName);
        }

        if (!SAML2_PROTOCOL_NS.equals(namespaceURI)) {
            throw new SamlProcessingException(
                    "SAML Response has incorrect namespace. Expected: " + SAML2_PROTOCOL_NS
                            + ", Found: " + namespaceURI);
        }

        String version = rootElement.getAttribute("Version");
        if (!"2.0".equals(version)) {
            throw new SamlProcessingException(
                    "Unsupported SAML version. Expected: 2.0, Found: " + version);
        }
    }

    private void validateStatus(Element responseElement) throws SamlProcessingException {
        NodeList statusList = responseElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "Status");
        if (statusList.getLength() == 0) {
            throw new SamlProcessingException("SAML Response missing Status element");
        }

        Element statusElement = (Element) statusList.item(0);
        NodeList statusCodeList = statusElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusCode");
        if (statusCodeList.getLength() == 0) {
            throw new SamlProcessingException("SAML Response missing StatusCode element");
        }

        Element statusCodeElement = (Element) statusCodeList.item(0);
        String statusValue = statusCodeElement.getAttribute("Value");

        if (!SAML_STATUS_SUCCESS.equals(statusValue)) {
            // Try to extract status message for better error reporting
            String statusMessage = "";
            NodeList statusMessageList = statusElement.getElementsByTagNameNS(SAML2_PROTOCOL_NS, "StatusMessage");
            if (statusMessageList.getLength() > 0) {
                statusMessage = statusMessageList.item(0).getTextContent();
            }
            throw new SamlProcessingException(
                    "SAML Response indicates failure. Status: " + statusValue
                            + (statusMessage.isEmpty() ? "" : ", Message: " + statusMessage));
        }
    }

    private String extractIssuer(Element parentElement) {
        NodeList issuerList = parentElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Issuer");
        if (issuerList.getLength() > 0) {
            // Get the first Issuer that is a direct child of the parent
            for (int i = 0; i < issuerList.getLength(); i++) {
                Node issuerNode = issuerList.item(i);
                if (issuerNode.getParentNode().equals(parentElement)) {
                    return issuerNode.getTextContent().trim();
                }
            }
        }
        return null;
    }

    private List<SamlAssertion> extractAssertions(Element responseElement) throws SamlProcessingException {
        List<SamlAssertion> assertions = new ArrayList<>();

        NodeList assertionList = responseElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Assertion");
        for (int i = 0; i < assertionList.getLength(); i++) {
            Element assertionElement = (Element) assertionList.item(i);
            SamlAssertion assertion = parseAssertion(assertionElement);
            assertions.add(assertion);
        }

        return assertions;
    }

    private SamlAssertion parseAssertion(Element assertionElement) throws SamlProcessingException {
        SamlAssertion assertion = new SamlAssertion();

        // Extract assertion ID
        String assertionId = assertionElement.getAttribute("ID");
        if (assertionId == null || assertionId.isEmpty()) {
            throw new SamlProcessingException("Assertion missing required 'ID' attribute");
        }
        assertion.setId(assertionId);

        // Extract issue instant
        String issueInstantStr = assertionElement.getAttribute("IssueInstant");
        if (issueInstantStr != null && !issueInstantStr.isEmpty()) {
            assertion.setIssueInstant(parseInstant(issueInstantStr));
        }

        // Extract Issuer
        String issuer = extractIssuer(assertionElement);
        assertion.setIssuer(issuer);

        // Extract Subject
        extractSubject(assertionElement, assertion);

        // Extract Conditions
        extractConditions(assertionElement, assertion);

        // Validate time conditions
        validateAssertionTimeConditions(assertion);

        // Extract AuthnStatement
        extractAuthnStatement(assertionElement, assertion);

        // Extract AttributeStatement
        extractAttributeStatement(assertionElement, assertion);

        return assertion;
    }

    private void extractSubject(Element assertionElement, SamlAssertion assertion) throws SamlProcessingException {
        NodeList subjectList = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Subject");
        if (subjectList.getLength() == 0) {
            throw new SamlProcessingException("Assertion missing Subject element");
        }

        Element subjectElement = (Element) subjectList.item(0);

        // Extract NameID
        NodeList nameIdList = subjectElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "NameID");
        if (nameIdList.getLength() > 0) {
            Element nameIdElement = (Element) nameIdList.item(0);
            assertion.setNameId(nameIdElement.getTextContent().trim());
            assertion.setNameIdFormat(nameIdElement.getAttribute("Format"));
        }

        // Extract SubjectConfirmation
        NodeList confirmationList = subjectElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "SubjectConfirmation");
        if (confirmationList.getLength() > 0) {
            Element confirmationElement = (Element) confirmationList.item(0);
            assertion.setSubjectConfirmationMethod(confirmationElement.getAttribute("Method"));

            NodeList confirmationDataList = confirmationElement.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "SubjectConfirmationData");
            if (confirmationDataList.getLength() > 0) {
                Element confirmationData = (Element) confirmationDataList.item(0);
                String notOnOrAfterStr = confirmationData.getAttribute("NotOnOrAfter");
                if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
                    assertion.setSubjectNotOnOrAfter(parseInstant(notOnOrAfterStr));
                }
                assertion.setRecipient(confirmationData.getAttribute("Recipient"));
            }
        }
    }

    private void extractConditions(Element assertionElement, SamlAssertion assertion) throws SamlProcessingException {
        NodeList conditionsList = assertionElement.getElementsByTagNameNS(SAML2_ASSERTION_NS, "Conditions");
        if (conditionsList.getLength() > 0) {
            Element conditionsElement = (Element) conditionsList.item(0);

            String notBeforeStr = conditionsElement.getAttribute("NotBefore");
            if (notBeforeStr != null && !notBeforeStr.isEmpty()) {
                assertion.setConditionsNotBefore(parseInstant(notBeforeStr));
            }

            String notOnOrAfterStr = conditionsElement.getAttribute("NotOnOrAfter");
            if (notOnOrAfterStr != null && !notOnOrAfterStr.isEmpty()) {
                assertion.setConditionsNotOnOrAfter(parseInstant(notOnOrAfterStr));
            }

            // Extract AudienceRestriction
            NodeList audienceRestrictionList = conditionsElement.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "AudienceRestriction");
            if (audienceRestrictionList.getLength() > 0) {
                Element audienceRestriction = (Element) audienceRestrictionList.item(0);
                NodeList audienceList = audienceRestriction.getElementsByTagNameNS(
                        SAML2_ASSERTION_NS, "Audience");
                List<String> audiences = new ArrayList<>();
                for (int i = 0; i < audienceList.getLength(); i++) {
                    audiences.add(audienceList.item(i).getTextContent().trim());
                }
                assertion.setAudiences(audiences);
            }
        }
    }

    private void validateAssertionTimeConditions(SamlAssertion assertion) throws SamlProcessingException {
        Instant now = Instant.now();
        int clockSkewSeconds = configuration.getClockSkewSeconds();

        if (assertion.getConditionsNotBefore() != null) {
            Instant adjustedNotBefore = assertion.getConditionsNotBefore().minusSeconds(clockSkewSeconds);
            if (now.isBefore(adjustedNotBefore)) {
                throw new SamlProcessingException(
                        "Assertion is not yet valid. NotBefore: " + assertion.getConditionsNotBefore());
            }
        }

        if (assertion.getConditionsNotOnOrAfter() != null) {
            Instant adjustedNotOnOrAfter = assertion.getConditionsNotOnOrAfter().plusSeconds(clockSkewSeconds);
            if (now.isAfter(adjustedNotOnOrAfter) || now.equals(adjustedNotOnOrAfter)) {
                throw new SamlProcessingException(
                        "Assertion has expired. NotOnOrAfter: " + assertion.getConditionsNotOnOrAfter());
            }
        }

        if (assertion.getSubjectNotOnOrAfter() != null) {
            Instant adjustedSubjectNotOnOrAfter = assertion.getSubjectNotOnOrAfter().plusSeconds(clockSkewSeconds);
            if (now.isAfter(adjustedSubjectNotOnOrAfter) || now.equals(adjustedSubjectNotOnOrAfter)) {
                throw new SamlProcessingException(
                        "Subject confirmation has expired. NotOnOrAfter: " + assertion.getSubjectNotOnOrAfter());
            }
        }

        // Validate audience restriction
        if (configuration.getExpectedAudience() != null && !configuration.getExpectedAudience().isEmpty()) {
            if (assertion.getAudiences() != null && !assertion.getAudiences().isEmpty()) {
                if (!assertion.getAudiences().contains(configuration.getExpectedAudience())) {
                    throw new SamlProcessingException(
                            "Audience restriction not satisfied. Expected: " + configuration.getExpectedAudience()
                                    + ", Found: " + assertion.getAudiences());
                }
            }
        }
    }

    private void extractAuthnStatement(Element assertionElement, SamlAssertion assertion) {
        NodeList authnStatementList = assertionElement.getElementsByTagNameNS(
                SAML2_ASSERTION_NS, "AuthnStatement");
        if (authnStatementList.getLength() > 0) {
            Element authnStatement = (Element) authnStatementList.item(0);

            String authnInstantStr = authnStatement.getAttribute("AuthnInstant");
            if (authnInstantStr != null && !authnInstantStr.isEmpty()) {
                try {
                    assertion.setAuthnInstant(Instant.parse(authnInstantStr));
                } catch (DateTimeParseException e) {
                    // Log but don't fail
                }
            }

            String sessionIndex = authnStatement.getAttribute("SessionIndex");
            assertion.setSessionIndex(sessionIndex);

            // Extract AuthnContext
            NodeList authnContextList = authnStatement.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "AuthnContext");
            if (authnContextList.getLength() > 0) {
                Element authnContext = (Element) authnContextList.item(0);
                NodeList authnContextClassRefList = authnContext.getElementsByTagNameNS(
                        SAML2_ASSERTION_NS, "AuthnContextClassRef");
                if (authnContextClassRefList.getLength() > 0) {
                    assertion.setAuthnContextClassRef(
                            authnContextClassRefList.item(0).getTextContent().trim());
                }
            }
        }
    }

    private void extractAttributeStatement(Element assertionElement, SamlAssertion assertion) {
        NodeList attrStatementList = assertionElement.getElementsByTagNameNS(
                SAML2_ASSERTION_NS, "AttributeStatement");
        if (attrStatementList.getLength() > 0) {
            Element attrStatement = (Element) attrStatementList.item(0);

            NodeList attributeList = attrStatement.getElementsByTagNameNS(
                    SAML2_ASSERTION_NS, "Attribute");
            Map<String, List<String>> attributes = new LinkedHashMap<>();

            for (int i = 0; i < attributeList.getLength(); i++) {
                Element attributeElement = (Element) attributeList.item(i);
                String attrName = attributeElement.getAttribute("Name");

                if (attrName == null || attrName.isEmpty()) {
                    continue;
                }

                List<String> values = new ArrayList<>();
                NodeList attrValueList = attributeElement.getElementsByTagNameNS(
                        SAML2_ASSERTION_NS, "AttributeValue");
                for (int j = 0; j < attrValueList.getLength(); j++) {
                    values.add(attrValueList.item(j).getTextContent().trim());
                }

                attributes.put(attrName, values);
            }

            assertion.setAttributes(attributes);
        }
    }

    private Instant parseInstant(String instantStr) throws SamlProcessingException {
        try {
            return Instant.parse(instantStr);
        } catch (DateTimeParseException e) {
            throw new SamlProcessingException("Invalid datetime format: " + instantStr, e);
        }
    }

    private AuthenticatedSession createAuthenticatedSession(SamlResponse samlResponse)
            throws SamlProcessingException {
        // Use the first assertion (primary assertion)
        SamlAssertion primaryAssertion = samlResponse.getAssertions().get(0);

        if (primaryAssertion.getNameId() == null || primaryAssertion.getNameId().isEmpty()) {
            throw new SamlProcessingException("No NameID found in the SAML assertion");
        }

        // Build user principal
        UserPrincipal userPrincipal = new UserPrincipal();
        userPrincipal.setNameId(primaryAssertion.getNameId());
        userPrincipal.setNameIdFormat(primaryAssertion.getNameIdFormat());
        userPrincipal.setIssuer(primaryAssertion.getIssuer());

        // Map attributes to user principal
        Map<String, List<String>> attributes = primaryAssertion.getAttributes();
        if (attributes != null) {
            userPrincipal.setAttributes(attributes);

            // Map well-known attributes
            mapWellKnownAttribute(attributes, "email", userPrincipal::setEmail);
            mapWellKnownAttribute(attributes, "mail", userPrincipal::setEmail);
            mapWellKnownAttribute(attributes,
                    "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/emailaddress",
                    userPrincipal::setEmail);

            mapWellKnownAttribute(attributes, "firstName", userPrincipal::setFirstName);
            mapWellKnownAttribute(attributes, "givenName", userPrincipal::setFirstName);
            mapWellKnownAttribute(attributes,
                    "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/givenname",
                    userPrincipal::setFirstName);

            mapWellKnownAttribute(attributes, "lastName", userPrincipal::setLastName);
            mapWellKnownAttribute(attributes, "sn", userPrincipal::setLastName);
            mapWellKnownAttribute(attributes,
                    "http://schemas.xmlsoap.org/ws/2005/05/identity/claims/surname",
                    userPrincipal::setLastName);

            mapWellKnownAttribute(attributes, "displayName", userPrincipal::setDisplayName);

            // Extract roles/groups
            List<String> roles = new ArrayList<>();
            if (attributes.containsKey("role")) {
                roles.addAll(attributes.get("role"));
            }
            if (attributes.containsKey("roles")) {
                roles.addAll(attributes.get("roles"));
            }
            if (attributes.containsKey("groups")) {
                roles.addAll(attributes.get("groups"));
            }
            if (attributes.containsKey(
                    "http://schemas.microsoft.com/ws/2008/06/identity/claims/role")) {
                roles.addAll(attributes.get(
                        "http://schemas.microsoft.com/ws/2008/06/identity/claims/role"));
            }
            userPrincipal.setRoles(roles);
        }

        // Create session
        AuthenticatedSession session = sessionManager.createSession(userPrincipal);
        session.setSamlResponseId(samlResponse.getId());
        session.setAssertionId(primaryAssertion.getId());
        session.setSessionIndex(primaryAssertion.getSessionIndex());
        session.setAuthnInstant(primaryAssertion.getAuthnInstant());
        session.setAuthnContextClassRef(primaryAssertion.getAuthnContextClassRef());

        return session;
    }

    private void mapWellKnownAttribute(Map<String, List<String>> attributes,
                                        String attributeName,
                                        java.util.function.Consumer<String> setter) {
        if (attributes.containsKey(attributeName)) {
            List<String> values = attributes.get(attributeName);
            if (values != null && !values.isEmpty() && !values.get(0).isEmpty()) {
                setter.accept(values.get(0));
            }
        }
    }

    public SessionManager getSessionManager() {
        return sessionManager;
    }

